import { useMemo, useState } from "react";
import {ScrollView, Text, TouchableOpacity} from "react-native";
import { Stack } from "expo-router";
import { useTheme } from "@/context/theme";
import { colors } from "@/constants/theme";
import GameCard, {Game} from "@/components/GameCard";
import {PLACEHOLDER_GAMES} from "@/constants/PLACEHOLDER_GAMES";
import { SymbolView, SymbolViewProps } from "expo-symbols";

// noinspection JSUnusedGlobalSymbols
export default function SearchIndex() {
  const [search, setSearch] = useState("");
  const [userGamenotesOnly, setUserGamenotesOnly] = useState(false);
  const PLACEHOLDER_IGRE = PLACEHOLDER_GAMES;

  const filteredGames = useMemo(() => {
    if (!search) return PLACEHOLDER_IGRE;
    return PLACEHOLDER_IGRE.filter((game) =>
      game.title.toLowerCase().includes(search.toLowerCase()),
    );
  }, [search]);

  const { theme } = useTheme();
  const t = colors[theme];

  return (
    <>
      <Stack.Screen
        options={{
          title: "Pretraži Gamenote",
          headerRight: () => (
            <TouchableOpacity
              onPress={() => console.log('sort')}
              style={{ justifyContent: 'center', alignItems: 'center', paddingLeft: 10 }}
            >
              <Text style={{ fontSize: 20, color: t.text }}>
                ↑↓
              </Text>
            </TouchableOpacity>
          ),
          headerLeft: () => (
            <TouchableOpacity
              onPress={() => setUserGamenotesOnly(prev => !prev)}
              style={{ justifyContent: 'center', alignItems: 'center', paddingRight: 10 }}
            >
              <SymbolView
                key={userGamenotesOnly ? "bookmark.fill" : "bookmark"}
                name={userGamenotesOnly ? "bookmark.fill" : "bookmark"}
                tintColor={t.tint}
                resizeMode="scaleAspectFit"
                style={{ width: 24, height: 24 }}
              />
            </TouchableOpacity>
          ),
          headerSearchBarOptions: {
            placeholder: "Pretraži Gamenote",
            onChangeText: (event) => setSearch(event.nativeEvent.text),
          },
        }}
      />
      <ScrollView
      style={{ backgroundColor: t.background }}
      contentContainerStyle={{ padding: 16, gap: 0 }}
      contentInsetAdjustmentBehavior="automatic"
    >
      {filteredGames.map((game, i) => (
        <GameCard key={i} game={game} />
      ))}
    </ScrollView>
    </>
  );
}

import { useMemo, useState } from "react";
import { ScrollView, TouchableOpacity } from "react-native";
import { Stack } from "expo-router";
import { useTheme } from "@/context/theme";
import { colors } from "@/constants/theme";
import GameCard from "@/components/GameCard";
import { PLACEHOLDER_GAMES } from "@/constants/PLACEHOLDER_GAMES";
import { SymbolView } from "expo-symbols";

// noinspection JSUnusedGlobalSymbols
export default function SearchIndex() {
  const [search, setSearch] = useState("");
  const [userGamenotesOnly, setUserGamenotesOnly] = useState(false);

  const filteredGames = useMemo(() => {
    if (!search) return PLACEHOLDER_GAMES;
    return PLACEHOLDER_GAMES.filter((game) =>
      game.title.toLowerCase().includes(search.toLowerCase()),
    );
  }, [search]);

  const { theme } = useTheme();
  const t = colors[theme];

  return (
    <>
      <Stack.Screen
        options={{
          title: "Pretraži Gamenote",
          headerRight: () => (
            <TouchableOpacity onPress={() => console.log('sort')}>
              <SymbolView
                name="arrow.up.arrow.down"
                tintColor={t.tint}
                resizeMode="scaleAspectFit"
                style={{ width: 22, height: 22 }}
              />
            </TouchableOpacity>
          ),
          headerLeft: () => (
            <TouchableOpacity onPress={() => setUserGamenotesOnly(prev => !prev)}>
              <SymbolView
                key={userGamenotesOnly ? "bookmark.fill" : "bookmark"}
                name={userGamenotesOnly ? "bookmark.fill" : "bookmark"}
                tintColor={t.tint}
                resizeMode="scaleAspectFit"
                style={{ width: 22, height: 22 }}
              />
            </TouchableOpacity>
          ),
          headerSearchBarOptions: {
            placeholder: "Pretraži Gamenote",
            onChangeText: (event) => setSearch(event.nativeEvent.text),
          },
        }}
      />
      <ScrollView
      style={{ backgroundColor: t.background }}
      contentContainerStyle={{ padding: 16, gap: 0 }}
      contentInsetAdjustmentBehavior="automatic"
    >
      {filteredGames.map((game, i) => (
        <GameCard key={i} game={game} />
      ))}
    </ScrollView>
    </>
  );
}
